  `amount` decimal(15,2) NOT NULL DEFAULT 0.00 COMMENT 'Số tiền giao dịch',
  `content` text DEFAULT NULL COMMENT 'Nội dung chuyển khoản',
  `reference_code` varchar(150) DEFAULT NULL COMMENT 'Mã tham chiếu',
  `invoice_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'ID hóa đơn tìm được',
  `company_invoice_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'ID hóa đơn công ty',
  `cashout_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'ID dòng tiền chi ra',
  `payment_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'ID thanh toán được tạo',
  `status` enum('pending','matched','processed','failed','duplicate') NOT NULL DEFAULT 'pending' COMMENT 'Trạng thái xử lý',
  `error_message` text DEFAULT NULL COMMENT 'Thông báo lỗi',
  `raw_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Dữ liệu đầy đủ từ webhook' CHECK (json_valid(`raw_data`)),
  `processed_at` datetime DEFAULT NULL COMMENT 'Thời gian xử lý',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ;

